"use client";

import React, { useState } from "react";
import { Form, Button, Container, Row, Col } from "react-bootstrap";

export default function Register() {
  const [step, setStep] = useState(1); // State to track the current step
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phoneNumber: "",
    country: "",
    idproof: "",
    password: "",
    confirmPassword: "",
    program: "",
    university: "",
    tenthCertificate: null,
    twelfthCertificate: null,
    otherCertificates: [],
  });


  const router = useRouter

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  const handleFileChange = (
    e: React.ChangeEvent<HTMLInputElement>,
    field: string
  ) => {
    if (e.target.files) {
      if (field === "otherCertificates") {
        setFormData({
          ...formData,
          [field]: Array.from(e.target.files),
        });
      } else {
        setFormData({
          ...formData,
          [field]: e.target.files[0],
        });
      }
    }
  };

  const nextStep = () => setStep((prevStep) => prevStep + 1);
  const prevStep = () => setStep((prevStep) => prevStep - 1);

  const submitHandler = (e: React.FormEvent) => {
    e.preventDefault();
    console.log("Form Data:", formData);


    
  };

  return (
    <Container className="d-flex justify-content-center align-items-center">
      <Row className="w-100 justify-content-center">
        <Col md={7}>
          <h2 className="text-center mb-4">Register</h2>
          <Form onSubmit={submitHandler}>
            {step === 1 && (
              <>
                <Form.Group className="mb-3" controlId="formName">
                  <Form.Label>Name</Form.Label>
                  <Form.Control
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your name"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formEmail">
                  <Form.Label>Email</Form.Label>
                  <Form.Control
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    type="email"
                    placeholder="Enter your email"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formPhoneNumber">
                  <Form.Label>Phone Number</Form.Label>
                  <Form.Control
                    name="phoneNumber"
                    value={formData.phoneNumber}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your phone number"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formCountry">
                  <Form.Label>Country</Form.Label>
                  <Form.Control
                    name="country"
                    value={formData.country}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your country"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formIdProof">
                  <Form.Label>ID Proof</Form.Label>
                  <Form.Control
                    name="idproof"
                    value={formData.idproof}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your ID proof"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formPassword">
                  <Form.Label>Password</Form.Label>
                  <Form.Control
                    name="password"
                    value={formData.password}
                    onChange={handleChange}
                    type="password"
                    placeholder="Enter your password"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formConfirmPassword">
                  <Form.Label>Confirm Password</Form.Label>
                  <Form.Control
                    name="confirmPassword"
                    value={formData.confirmPassword}
                    onChange={handleChange}
                    type="password"
                    placeholder="Confirm your password"
                  />
                </Form.Group>

                <Button variant="primary" onClick={nextStep} className="w-100">
                  Next
                </Button>
              </>
            )}

            {step === 2 && (
              <>
                <Form.Group className="mb-3" controlId="formProgram">
                  <Form.Label>Select Program</Form.Label>
                  <Form.Select
                    name="program"
                    value={formData.program}
                    onChange={handleChange}
                  >
                    <option value="">Select a program</option>
                    <option value="B.Tech">B.Tech</option>
                    <option value="M.Tech">M.Tech</option>
                    <option value="MBA">MBA</option>
                  </Form.Select>
                </Form.Group>

                <Form.Group className="mb-3" controlId="formUniversity">
                  <Form.Label>Select University</Form.Label>
                  <Form.Select
                    name="university"
                    value={formData.university}
                    onChange={handleChange}
                  >
                    <option value="">Select a university</option>
                    <option value="University A">University A</option>
                    <option value="University B">University B</option>
                    <option value="University C">University C</option>
                  </Form.Select>
                </Form.Group>

                <Button variant="secondary" onClick={prevStep} className="me-2">
                  Back
                </Button>
                <Button variant="primary" onClick={nextStep}>
                  Next
                </Button>
              </>
            )}

            {step === 3 && (
              <>
                <Form.Group className="mb-3" controlId="formTenthCertificate">
                  <Form.Label>10th Certificate</Form.Label>
                  <Form.Control
                    type="file"
                    onChange={(e) => handleFileChange(e, "tenthCertificate")}
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formTwelfthCertificate">
                  <Form.Label>12th Certificate</Form.Label>
                  <Form.Control
                    type="file"
                    onChange={(e) => handleFileChange(e, "twelfthCertificate")}
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formOtherCertificates">
                  <Form.Label>Other Certificates</Form.Label>
                  <Form.Control
                    type="file"
                    multiple
                    onChange={(e) => handleFileChange(e, "otherCertificates")}
                  />
                </Form.Group>

                <Button variant="secondary" onClick={prevStep} className="me-2">
                  Back
                </Button>
                <Button  variant="success" type="submit">
                  Submit
                </Button>
              </>
            )}
          </Form>
        </Col>
      </Row>
    </Container>
  )
}
